\draw[cGray!12, line width=0.25pt] (9.47, 0.14) -- (9.47, 4.36);

% Compact bias module: a restrained instrument cue, not the visual subject.
\fill[cGray!30!black, opacity=0.018]
  (12.58, 3.78) rectangle (13.48, 4.14);
\fill[cGray!3] (12.56, 3.82) rectangle (13.46, 4.16);
\draw[cGray!58!black, line width=0.22pt, rounded corners=1.0pt]
  (12.56, 3.82) rectangle (13.46, 4.16);
\draw[cGray!78!black, line width=0.24pt]
  (12.66, 4.01) rectangle (13.12, 4.10);
\draw[cGray!48!black, line width=0.24pt]
  (12.70, 4.045) -- (12.83, 4.045) -- (12.83, 4.075)
               -- (12.98, 4.075) -- (12.98, 4.045) -- (13.08, 4.045);
\node[font=\sffamily\bfseries\fontsize{3.9}{4.7}\selectfont, text=cGray!74!black]
  at (12.99, 3.94) {$V_{\mathrm{active}}$};
\node[font=\sffamily\fontsize{3.0}{3.6}\selectfont, text=cGray!54!black]
  at (12.99, 3.84) {bias};
\fill[cRed!68!black] (13.30, 3.82) circle (0.020);
\fill[cGray!55!black] (13.30, 2.82) circle (0.020);
\draw[cGray!62!black, line width=0.34pt, rounded corners=0.8pt]
  (13.30, 3.78) -- (13.30, 2.82);

% Fixed clip and charge-trapping cantilever.
\fill[cGray!10] (11.55, 2.84) rectangle (12.10, 2.96);
\draw[cGray!75!black, line width=0.38pt] (11.55, 2.84) rectangle (12.10, 2.96);
\draw[cGray!55!black, line width=0.38pt] (11.42, 3.10) -- (12.22, 3.10);
\foreach \dx in {0,0.11,0.22,0.33,0.44,0.55,0.66} {
  \draw[cGray!55!black, line width=0.25pt]
    ({11.42+\dx}, 3.10) -- ({11.36+\dx}, 3.18);
}
\draw[cGray!75!black, line width=0.35pt] (11.82, 2.96) -- (11.82, 3.10);

